const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');

const app = express();

// ============================================================================
// Configuration
// ============================================================================
const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';
const CORS_ORIGIN = process.env.CORS_ORIGIN || 'http://localhost:3000';

// Static data - cached outside request handlers to prevent reconstruction
const USERS_DATA = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

// ============================================================================
// Security Middleware
// ============================================================================

// Add security headers
app.use(helmet());

// Enable CORS with explicit configuration
app.use(cors({
  origin: CORS_ORIGIN.split(',').map(o => o.trim()),
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
}));

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Body parser for JSON
app.use(express.json({ limit: '10kb' })); // Prevent large payload attacks

// ============================================================================
// Routes
// ============================================================================

/**
 * Health check endpoint - for monitoring/orchestration
 * Returns service status and current timestamp
 */
app.get('/health', (req, res) => {
  try {
    res.status(200).json({
      status: 'ok',
      timestamp: new Date().toISOString(),
      environment: NODE_ENV,
    });
  } catch (error) {
    handleError(error, res, 500, 'Health check failed');
  }
});

/**
 * Get users endpoint - returns list of users
 * NOTE: In production, should require authentication and filter sensitive data
 */
app.get('/users', (req, res) => {
  try {
    // Validate query parameters
    const page = parseInt(req.query.page, 10) || 1;
    const limit = parseInt(req.query.limit, 10) || 10;

    // Validate pagination parameters
    if (page < 1 || limit < 1 || limit > 100) {
      return res.status(400).json({
        success: false,
        error: 'Invalid pagination parameters. Page and limit must be positive, limit ≤ 100.',
      });
    }

    // Filter sensitive data - remove emails in production
    const sanitizedUsers = USERS_DATA.map(user => ({
      id: user.id,
      name: user.name,
      // In production, decide if email should be exposed
      // Remove for non-authenticated requests
      email: user.email,
    }));

    // Apply pagination
    const startIndex = (page - 1) * limit;
    const endIndex = startIndex + limit;
    const paginatedUsers = sanitizedUsers.slice(startIndex, endIndex);

    res.status(200).json({
      success: true,
      data: paginatedUsers,
      pagination: {
        page,
        limit,
        total: sanitizedUsers.length,
      },
      timestamp: new Date().toISOString(),
    });
  } catch (error) {
    handleError(error, res, 500, 'Failed to fetch users');
  }
});

// ============================================================================
// Error Handling
// ============================================================================

/**
 * Helper function for consistent error response formatting
 */
function handleError(error, res, statusCode = 500, message = 'An error occurred') {
  console.error(`[${new Date().toISOString()}] Error: ${message}`, error);

  // Don't expose internal error details to client in production
  const clientMessage = NODE_ENV === 'production'
    ? message
    : `${message}: ${error.message}`;

  res.status(statusCode).json({
    success: false,
    error: clientMessage,
    ...(NODE_ENV !== 'production' && { details: error.message }),
  });
}

// 404 handler for undefined routes
app.use((req, res) => {
  res.status(404).json({
    success: false,
    error: 'Resource not found',
    path: req.path,
  });
});

// Global error handler middleware (must be last)
app.use((error, req, res, next) => {
  const statusCode = error.statusCode || 500;
  handleError(error, res, statusCode, error.message || 'Internal server error');
});

// ============================================================================
// Server Startup and Graceful Shutdown
// ============================================================================

let server;

const startServer = () => {
  server = app.listen(PORT, () => {
    console.log(`[${new Date().toISOString()}] Server running on port ${PORT} (${NODE_ENV})`);
  });

  // Handle graceful shutdown
  process.on('SIGTERM', () => {
    console.log('[SIGTERM] Shutting down gracefully...');
    server.close(() => {
      console.log('Server closed');
      process.exit(0);
    });

    // Force shutdown after 10 seconds
    setTimeout(() => {
      console.error('Could not close connections in time, forcefully shutting down');
      process.exit(1);
    }, 10000);
  });

  process.on('SIGINT', () => {
    console.log('[SIGINT] Shutting down gracefully...');
    server.close(() => {
      console.log('Server closed');
      process.exit(0);
    });
  });

  // Handle uncaught exceptions
  process.on('uncaughtException', (error) => {
    console.error('Uncaught Exception:', error);
